  "inlineSchema": "// ============================================\n// Jurista — Prisma Schema\n// ============================================\n// Sistema de gerenciamento de empréstimos pessoais\n// PostgreSQL 16+ | Prisma 6.x\n// ============================================\n\ngenerator client {\n  provider      = \"prisma-client-js\"\n  binaryTargets = [\"native\", \"linux-musl-openssl-3.0.x\"]\n  output        = \"./generated/client\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ==================== ENUMS ====================\n\nenum UserRole {\n  MASTER\n  COLLECTOR\n}\n\nenum LoanFrequency {\n  DAILY\n  WEEKLY\n  BIWEEKLY\n  MONTHLY\n}\n\nenum LoanStatus {\n  ACTIVE\n  COMPLETED\n  DEFAULTED\n  RENEWED\n}\n\nenum InstallmentStatus {\n  PENDING\n  PAID\n  OVERDUE\n  PARTIALLY_PAID\n}\n\nenum PaymentMethod {\n  PIX\n  CASH\n}\n\nenum CashMovementType {\n  INCOME\n  EXPENSE\n  WITHDRAWAL\n  DEPOSIT\n}\n\n// ==================== MODELS ====================\n\n/// Usuários do sistema (Master e Cobradores)\nmodel User {\n  id            String   @id @default(cuid())\n  name          String\n  email         String   @unique\n  passwordHash  String /// Argon2id hash\n  role          UserRole\n  phone         String?\n  active        Boolean  @default(true)\n  commissionPct Decimal? @db.Decimal(5, 2) /// % comissão padrão do cobrador\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  loans         Loan[]         @relation(\"CollectorLoans\")\n  payments      Payment[]      @relation(\"CollectorPayments\")\n  cashMovements CashMovement[]\n\n  @@index([role])\n  @@index([active])\n  @@map(\"users\")\n}\n\n/// Clientes que recebem empréstimos\nmodel Client {\n  id          String  @id @default(cuid())\n  name        String\n  cpf         String  @unique\n  rg          String\n  address     String\n  phone1      String\n  phone2      String?\n  creditScore Int     @default(0) /// Pontuação interna (0-100)\n  active      Boolean @default(true)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  photos ClientPhoto[]\n  loans  Loan[]\n\n  @@index([name])\n  @@index([active])\n  @@map(\"clients\")\n}\n\n/// Fotos do cliente armazenadas no MinIO\nmodel ClientPhoto {\n  id           String  @id @default(cuid())\n  clientId     String\n  bucket       String  @default(\"client-photos\")\n  objectKey    String /// MinIO object key: {clientId}/{uuid}.{ext}\n  originalName String /// Nome original do arquivo\n  type         String /// \"rg\" | \"selfie\" | \"facade\" | \"other\"\n  description  String?\n  sizeBytes    Int?\n  mimeType     String?\n\n  createdAt DateTime @default(now())\n\n  // Relations\n  client Client @relation(fields: [clientId], references: [id], onDelete: Cascade)\n\n  @@index([clientId])\n  @@index([type])\n  @@map(\"client_photos\")\n}\n\n/// Empréstimos concedidos a clientes\nmodel Loan {\n  id                String        @id @default(cuid())\n  clientId          String\n  collectorId       String /// Cobrador responsável\n  amount            Decimal       @db.Decimal(12, 2) /// Valor emprestado\n  interestRate      Decimal       @db.Decimal(5, 2) /// Taxa de juros (%)\n  totalWithInterest Decimal       @db.Decimal(12, 2) /// Valor + juros\n  frequency         LoanFrequency\n  totalInstallments Int /// Nº total de parcelas\n  installmentAmount Decimal       @db.Decimal(12, 2) /// Valor de cada parcela\n  status            LoanStatus    @default(ACTIVE)\n  commissionPct     Decimal       @db.Decimal(5, 2) /// % comissão cobrador\n  commissionAmount  Decimal       @db.Decimal(12, 2) /// Valor total da comissão\n  lateFeeAmount     Decimal       @default(10) @db.Decimal(12, 2) /// R$ multa por intervalo\n  lateFeeDays       Int           @default(5) /// A cada X dias de atraso\n  startDate         DateTime\n  endDate           DateTime?\n  previousLoanId    String?       @unique /// Referência para renovação\n  notes             String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  client       Client        @relation(fields: [clientId], references: [id])\n  collector    User          @relation(\"CollectorLoans\", fields: [collectorId], references: [id])\n  installments Installment[]\n  previousLoan Loan?         @relation(\"LoanRenewal\", fields: [previousLoanId], references: [id])\n  renewedLoan  Loan?         @relation(\"LoanRenewal\")\n\n  @@index([clientId])\n  @@index([collectorId])\n  @@index([status])\n  @@index([startDate])\n  @@map(\"loans\")\n}\n\n/// Parcelas de um empréstimo\nmodel Installment {\n  id            String            @id @default(cuid())\n  loanId        String\n  installmentNo Int /// Número da parcela (1, 2, 3...)\n  amount        Decimal           @db.Decimal(12, 2) /// Valor original\n  lateFee       Decimal           @default(0) @db.Decimal(12, 2) /// Multa acumulada\n  totalDue      Decimal           @db.Decimal(12, 2) /// amount + lateFee\n  dueDate       DateTime /// Data de vencimento (pula domingos)\n  status        InstallmentStatus @default(PENDING)\n  paidAmount    Decimal           @default(0) @db.Decimal(12, 2)\n  paidAt        DateTime?\n  daysOverdue   Int               @default(0)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  loan     Loan      @relation(fields: [loanId], references: [id], onDelete: Cascade)\n  payments Payment[]\n\n  @@index([loanId])\n  @@index([status])\n  @@index([dueDate])\n  @@index([loanId, installmentNo])\n  @@map(\"installments\")\n}\n\n/// Pagamentos recebidos\nmodel Payment {\n  id            String        @id @default(cuid())\n  installmentId String\n  collectorId   String /// Quem recebeu o pagamento\n  amount        Decimal       @db.Decimal(12, 2)\n  method        PaymentMethod\n  receivedAt    DateTime      @default(now())\n  notes         String?\n  syncId        String?       @unique /// ID para sync offline\n\n  createdAt DateTime @default(now())\n\n  // Relations\n  installment  Installment   @relation(fields: [installmentId], references: [id])\n  collector    User          @relation(\"CollectorPayments\", fields: [collectorId], references: [id])\n  cashMovement CashMovement?\n\n  @@index([installmentId])\n  @@index([collectorId])\n  @@index([receivedAt])\n  @@index([method])\n  @@map(\"payments\")\n}\n\n/// Movimentações do caixa\nmodel CashMovement {\n  id          String           @id @default(cuid())\n  userId      String /// Quem realizou\n  paymentId   String?          @unique /// Vínculo com pagamento\n  type        CashMovementType\n  amount      Decimal          @db.Decimal(12, 2)\n  description String?\n  date        DateTime         @default(now())\n\n  createdAt DateTime @default(now())\n\n  // Relations\n  user    User     @relation(fields: [userId], references: [id])\n  payment Payment? @relation(fields: [paymentId], references: [id])\n\n  @@index([userId])\n  @@index([type])\n  @@index([date])\n  @@map(\"cash_movements\")\n}\n\n/// Configurações do sistema (chave-valor)\nmodel SystemConfig {\n  id          String  @id @default(cuid())\n  key         String  @unique\n  value       String\n  description String?\n\n  updatedAt DateTime @updatedAt\n\n  @@map(\"system_configs\")\n}\n\n/// Fila de sincronização offline (Outbox Pattern)\nmodel SyncQueue {\n  id         String  @id @default(cuid())\n  entityType String /// \"payment\" | \"client\" | \"loan\" | etc.\n  entityId   String /// ID da entidade\n  action     String /// \"create\" | \"update\" | \"delete\"\n  payload    Json /// Dados da operação\n  syncId     String  @unique /// UUID gerado no mobile\n  synced     Boolean @default(false)\n  attempts   Int     @default(0)\n  lastError  String?\n\n  createdAt DateTime  @default(now())\n  syncedAt  DateTime?\n\n  @@index([synced])\n  @@index([entityType])\n  @@index([createdAt])\n  @@map(\"sync_queue\")\n}\n",
